        {"id":"drv8825","name":"DRV8825 Stepper Driver","libs":[],"lib_deps":[],"pins":{"step":25,"dir":26,"enable":27,"m0":12,"m1":14,"m2":13},
         "header":'#ifndef DRV8825_H\n#define DRV8825_H\nvoid drv8825_setup();\nvoid drv8825_move(int steps, bool cw);\nvoid drv8825_set_microstep(uint8_t mode);\nvoid drv8825_enable(bool en);\n#endif',
         "source":'#include "drv8825.h"\n#include <Arduino.h>\n#define STEP_P 25\n#define DIR_P 26\n#define EN_P 27\n#define M0_P 12\n#define M1_P 14\n#define M2_P 13\nstatic int _stepsLeft=0;static bool _cw=true;static unsigned long _lastStep=0;static unsigned long _stepDelay=500;\nvoid drv8825_setup(){pinMode(STEP_P,OUTPUT);pinMode(DIR_P,OUTPUT);pinMode(EN_P,OUTPUT);pinMode(M0_P,OUTPUT);pinMode(M1_P,OUTPUT);pinMode(M2_P,OUTPUT);digitalWrite(EN_P,LOW);Serial.println("[drv8825] OK");}\nvoid drv8825_move(int s,bool cw){_stepsLeft=abs(s);_cw=cw;digitalWrite(DIR_P,cw?HIGH:LOW);while(_stepsLeft>0){digitalWrite(STEP_P,HIGH);delayMicroseconds(2);digitalWrite(STEP_P,LOW);delayMicroseconds(_stepDelay);_stepsLeft--;}}\nvoid drv8825_set_microstep(uint8_t m){digitalWrite(M0_P,m&1);digitalWrite(M1_P,(m>>1)&1);digitalWrite(M2_P,(m>>2)&1);}\nvoid drv8825_enable(bool e){digitalWrite(EN_P,e?LOW:HIGH);}'},
        {"id":"tb6612fng","name":"TB6612FNG Dual Motor","libs":[],"lib_deps":[],"pins":{"ain1":25,"ain2":26,"pwma":27,"bin1":14,"bin2":12,"pwmb":13,"stby":33},
         "header":'#ifndef TB6612_H\n#define TB6612_H\nvoid tb6612_setup();\nvoid tb6612_motor_a(int speed);\nvoid tb6612_motor_b(int speed);\nvoid tb6612_brake();\nvoid tb6612_standby(bool en);\n#endif',
         "source":'#include "tb6612fng.h"\n#include <Arduino.h>\n#define AIN1 25\n#define AIN2 26\n#define PWMA 27\n#define BIN1 14\n#define BIN2 12\n#define PWMB 13\n#define STBY 33\nvoid tb6612_setup(){pinMode(AIN1,OUTPUT);pinMode(AIN2,OUTPUT);pinMode(BIN1,OUTPUT);pinMode(BIN2,OUTPUT);pinMode(STBY,OUTPUT);ledcAttach(PWMA,5000,8);ledcAttach(PWMB,5000,8);digitalWrite(STBY,HIGH);Serial.println("[tb6612] OK");}\nvoid tb6612_motor_a(int s){if(s>0){digitalWrite(AIN1,HIGH);digitalWrite(AIN2,LOW);}else if(s<0){digitalWrite(AIN1,LOW);digitalWrite(AIN2,HIGH);s=-s;}else{digitalWrite(AIN1,LOW);digitalWrite(AIN2,LOW);}ledcWrite(PWMA,constrain(s,0,255));}\nvoid tb6612_motor_b(int s){if(s>0){digitalWrite(BIN1,HIGH);digitalWrite(BIN2,LOW);}else if(s<0){digitalWrite(BIN1,LOW);digitalWrite(BIN2,HIGH);s=-s;}else{digitalWrite(BIN1,LOW);digitalWrite(BIN2,LOW);}ledcWrite(PWMB,constrain(s,0,255));}\nvoid tb6612_brake(){tb6612_motor_a(0);tb6612_motor_b(0);}\nvoid tb6612_standby(bool e){digitalWrite(STBY,e?LOW:HIGH);}'},
