        {"id":"pid_controller","name":"PID Controller","libs":[],"lib_deps":[],"pins":{},
         "header":'#ifndef PID_CTRL_H\n#define PID_CTRL_H\nvoid pid_setup(float kp,float ki,float kd);\nfloat pid_compute(float setpoint,float input);\nvoid pid_set_limits(float min,float max);\nvoid pid_reset();\n#endif',
         "source":'#include "pid_controller.h"\n#include <Arduino.h>\nstatic float _kp=1,_ki=0,_kd=0;\nstatic float _integral=0,_prevErr=0,_output=0;\nstatic float _min=-255,_max=255;\nstatic unsigned long _last=0;\nvoid pid_setup(float kp,float ki,float kd){_kp=kp;_ki=ki;_kd=kd;_integral=0;_prevErr=0;_last=millis();Serial.printf("[pid] Kp=%.2f Ki=%.2f Kd=%.2f\\n",kp,ki,kd);}\nfloat pid_compute(float sp,float in){unsigned long now=millis();float dt=(now-_last)/1000.0;if(dt<=0)dt=0.001;_last=now;float err=sp-in;_integral+=err*dt;float deriv=(err-_prevErr)/dt;_prevErr=err;_output=_kp*err+_ki*_integral+_kd*deriv;if(_output>_max)_output=_max;if(_output<_min)_output=_min;return _output;}\nvoid pid_set_limits(float mn,float mx){_min=mn;_max=mx;}\nvoid pid_reset(){_integral=0;_prevErr=0;}'},
        {"id":"kalman_filter","name":"Kalman Filter","libs":[],"lib_deps":[],"pins":{},
         "header":'#ifndef KALMAN_H\n#define KALMAN_H\nvoid kalman_setup(float q,float r,float initial);\nfloat kalman_update(float measurement);\nfloat kalman_get_estimate();\n#endif',
         "source":'#include "kalman_filter.h"\nstatic float _q=0.01,_r=0.1,_x=0,_p=1,_k=0;\nvoid kalman_setup(float q,float r,float init){_q=q;_r=r;_x=init;_p=1;}\nfloat kalman_update(float z){_p+=_q;_k=_p/(_p+_r);_x+=_k*(z-_x);_p*=(1-_k);return _x;}\nfloat kalman_get_estimate(){return _x;}'},
        {"id":"state_machine","name":"Finite State Machine","libs":[],"lib_deps":[],"pins":{},
         "header":'#ifndef FSM_H\n#define FSM_H\n#include <Arduino.h>\ntypedef void(*state_fn)();\nvoid fsm_setup(uint8_t num_states);\nvoid fsm_set_state(uint8_t id, state_fn enter, state_fn run, state_fn exit_fn);\nvoid fsm_transition(uint8_t id);\nvoid fsm_loop();\nuint8_t fsm_current_state();\n#endif',
         "source":'#include "state_machine.h"\n#define MAX_STATES 16\nstatic struct{state_fn enter;state_fn run;state_fn exit_fn;}_states[MAX_STATES];\nstatic uint8_t _current=0,_numStates=0;\nvoid fsm_setup(uint8_t n){_numStates=min(n,(uint8_t)MAX_STATES);_current=0;Serial.printf("[fsm] OK %d states\\n",_numStates);}\nvoid fsm_set_state(uint8_t id,state_fn e,state_fn r,state_fn x){if(id<MAX_STATES){_states[id]={e,r,x};}}\nvoid fsm_transition(uint8_t id){if(id>=_numStates)return;if(_states[_current].exit_fn)_states[_current].exit_fn();_current=id;if(_states[_current].enter)_states[_current].enter();}\nvoid fsm_loop(){if(_states[_current].run)_states[_current].run();}\nuint8_t fsm_current_state(){return _current;}'},
        {"id":"timer_scheduler","name":"Timer/Scheduler","libs":[],"lib_deps":[],"pins":{},
         "header":'#ifndef TIMER_SCHED_H\n#define TIMER_SCHED_H\n#include <Arduino.h>\ntypedef void(*timer_cb)();\nvoid scheduler_setup();\nuint8_t scheduler_add(uint32_t interval_ms,timer_cb callback);\nvoid scheduler_remove(uint8_t id);\nvoid scheduler_loop();\n#endif',
         "source":'#include "timer_scheduler.h"\n#define MAX_TIMERS 16\nstatic struct{uint32_t interval;timer_cb cb;unsigned long last;bool active;}_timers[MAX_TIMERS];\nstatic uint8_t _count=0;\nvoid scheduler_setup(){for(int i=0;i<MAX_TIMERS;i++)_timers[i].active=false;Serial.println("[sched] OK");}\nuint8_t scheduler_add(uint32_t ms,timer_cb cb){if(_count>=MAX_TIMERS)return 255;uint8_t id=_count++;_timers[id]={ms,cb,millis(),true};return id;}\nvoid scheduler_remove(uint8_t id){if(id<MAX_TIMERS)_timers[id].active=false;}\nvoid scheduler_loop(){unsigned long now=millis();for(int i=0;i<_count;i++){if(_timers[i].active&&now-_timers[i].last>=_timers[i].interval){_timers[i].last=now;_timers[i].cb();}}}'},
        {"id":"watchdog","name":"Hardware Watchdog","libs":[],"lib_deps":[],"pins":{},
         "header":'#ifndef WATCHDOG_H\n#define WATCHDOG_H\nvoid watchdog_setup(uint32_t timeout_ms);\nvoid watchdog_feed();\nvoid watchdog_disable();\n#endif',
         "source":'#include "watchdog.h"\n#include <esp_task_wdt.h>\nvoid watchdog_setup(uint32_t ms){esp_task_wdt_config_t cfg={.timeout_ms=ms,.idle_core_mask=(1<<0)|(1<<1),.trigger_panic=true};esp_task_wdt_init(&cfg);esp_task_wdt_add(NULL);Serial.printf("[wdt] OK %ldms\\n",(long)ms);}\nvoid watchdog_feed(){esp_task_wdt_reset();}\nvoid watchdog_disable(){esp_task_wdt_delete(NULL);}'},
        {"id":"moving_average","name":"Moving Average Filter","libs":[],"lib_deps":[],"pins":{},
         "header":'#ifndef MAVG_H\n#define MAVG_H\nvoid mavg_setup(uint8_t window_size);\nfloat mavg_add(float value);\nfloat mavg_get();\nvoid mavg_reset();\n#endif',
         "source":'#include "moving_average.h"\n#define MAX_WINDOW 64\nstatic float _buf[MAX_WINDOW];\nstatic uint8_t _size=10,_idx=0,_count=0;\nstatic float _sum=0;\nvoid mavg_setup(uint8_t w){_size=min(w,(uint8_t)MAX_WINDOW);_idx=0;_count=0;_sum=0;}\nfloat mavg_add(float v){if(_count<_size){_buf[_idx]=v;_sum+=v;_count++;}else{_sum-=_buf[_idx];_buf[_idx]=v;_sum+=v;}_idx=(_idx+1)%_size;return _sum/_count;}\nfloat mavg_get(){return _count>0?_sum/_count:0;}\nvoid mavg_reset(){_idx=0;_count=0;_sum=0;}'},
        {"id":"data_logger","name":"CSV Data Logger","libs":[],"lib_deps":[],"pins":{},
         "header":'#ifndef DATA_LOGGER_H\n#define DATA_LOGGER_H\n#include <Arduino.h>\nvoid logger_setup(const char* filename);\nvoid logger_add_field(const char* name, float value);\nvoid logger_write_row();\nuint32_t logger_get_rows();\n#endif',
         "source":'#include "data_logger.h"\n#include <SD.h>\nstatic String _filename;\nstatic String _row;\nstatic uint32_t _rows=0;\nstatic bool _first=true;\nvoid logger_setup(const char*fn){_filename=fn;_rows=0;Serial.printf("[logger] OK -> %s\\n",fn);}\nvoid logger_add_field(const char*n,float v){if(!_row.isEmpty())_row+=",";if(_first)_row+=String(n)+":";_row+=String(v,2);}\nvoid logger_write_row(){File f=SD.open(_filename,FILE_APPEND);if(f){f.println(_row);f.close();_rows++;}_row="";_first=false;}\nuint32_t logger_get_rows(){return _rows;}'},
        {"id":"json_builder","name":"JSON Builder","libs":["ArduinoJson.h"],"lib_deps":["bblanchon/ArduinoJson@^7.0.0"],"pins":{},
         "header":'#ifndef JSON_BUILDER_H\n#define JSON_BUILDER_H\n#include <ArduinoJson.h>\nvoid json_begin();\nvoid json_add_string(const char*key,const char*val);\nvoid json_add_float(const char*key,float val);\nvoid json_add_int(const char*key,int val);\nvoid json_add_bool(const char*key,bool val);\nString json_serialize();\n#endif',
         "source":'#include "json_builder.h"\nstatic JsonDocument _doc;\nvoid json_begin(){_doc.clear();}\nvoid json_add_string(const char*k,const char*v){_doc[k]=v;}\nvoid json_add_float(const char*k,float v){_doc[k]=v;}\nvoid json_add_int(const char*k,int v){_doc[k]=v;}\nvoid json_add_bool(const char*k,bool v){_doc[k]=v;}\nString json_serialize(){String s;serializeJson(_doc,s);return s;}'},
