        {"id":"solar_mppt","name":"Solar MPPT Monitor","libs":["Wire.h","Adafruit_INA219.h"],"lib_deps":["adafruit/Adafruit INA219@^1.2.1"],"pins":{"sda":21,"scl":22},"bus":"I2C",
         "header":'#ifndef SOLAR_H\n#define SOLAR_H\nvoid solar_setup();\nvoid solar_loop();\nfloat solar_get_voltage();\nfloat solar_get_current();\nfloat solar_get_power();\nfloat solar_get_energy_wh();\n#endif',
         "source":'#include "solar_mppt.h"\n#include <Wire.h>\n#include <Adafruit_INA219.h>\nstatic Adafruit_INA219 ina;\nstatic float _v=0,_mA=0,_mW=0,_wh=0;\nstatic unsigned long _last=0;\nvoid solar_setup(){Wire.begin();ina.begin();ina.setCalibration_32V_2A();Serial.println("[solar] OK");}\nvoid solar_loop(){if(millis()-_last<1000)return;unsigned long dt=millis()-_last;_last=millis();_v=ina.getBusVoltage_V();_mA=ina.getCurrent_mA();_mW=ina.getPower_mW();_wh+=_mW*dt/3600000.0;}\nfloat solar_get_voltage(){return _v;}\nfloat solar_get_current(){return _mA;}\nfloat solar_get_power(){return _mW;}\nfloat solar_get_energy_wh(){return _wh;}'},
        {"id":"power_relay_timer","name":"Power Relay Timer","libs":[],"lib_deps":[],"pins":{"relay":25},
         "header":'#ifndef POWER_TIMER_H\n#define POWER_TIMER_H\nvoid power_timer_setup();\nvoid power_timer_on_for(uint32_t seconds);\nvoid power_timer_off_for(uint32_t seconds);\nvoid power_timer_schedule(uint8_t on_hour,uint8_t on_min,uint8_t off_hour,uint8_t off_min);\nvoid power_timer_loop();\nbool power_timer_state();\n#endif',
         "source":'#include "power_relay_timer.h"\n#include <Arduino.h>\n#define RELAY_PIN 25\nstatic bool _state=false;\nstatic unsigned long _switchAt=0;\nstatic bool _timedAction=false;\nvoid power_timer_setup(){pinMode(RELAY_PIN,OUTPUT);digitalWrite(RELAY_PIN,HIGH);Serial.println("[power] OK");}\nvoid power_timer_on_for(uint32_t s){digitalWrite(RELAY_PIN,LOW);_state=true;_switchAt=millis()+s*1000;_timedAction=true;}\nvoid power_timer_off_for(uint32_t s){digitalWrite(RELAY_PIN,HIGH);_state=false;_switchAt=millis()+s*1000;_timedAction=true;}\nvoid power_timer_schedule(uint8_t oh,uint8_t om,uint8_t fh,uint8_t fm){}\nvoid power_timer_loop(){if(_timedAction&&millis()>=_switchAt){_state=!_state;digitalWrite(RELAY_PIN,_state?LOW:HIGH);_timedAction=false;}}\nbool power_timer_state(){return _state;}'},
